/* Embedded site images kept here so index.html stays readable. */
window.IMGS = {
  amethyst:     'data:image/jpeg;base64,',
  jasper:       'data:image/jpeg;base64,',
  turquoiseSet: 'data:image/jpeg;base64,',
  turquoiseSlab:'data:image/jpeg;base64,',
};
// inject all lazy images
document.querySelectorAll('[data-src]').forEach(el => { el.src = IMGS[el.dataset.src] || ''; });

